import React from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { setX, setY, setR, addResult } from '../store/app/appActions';

const X_VALUES = [-3, -2, -1, 0, 1, 2, 3, 4, 5];
const R_VALUES = [-3, -2, -1, 0, 1, 2, 3, 4, 5];

const PointForm = () => {
  const dispatch = useDispatch();
  const { x, y, r } = useSelector(state => state.app);
  
  return (
	<div className="box">
      <h3>Параметры точки</h3>

      <div>
        <label>X:</label>
        {-3,-2,-1,0,1,2,3,4,5}
      </div>

      <div>
        <label>Y:</label>
        <input type="text" placeholder="-3 ... 3" />
      </div>

      <div>
        <label>R:</label>
        {-3,-2,-1,0,1,2,3,4,5}
      </div>

      <button>Проверить</button>
    </div>
  );
};

export default PointForm;
